        lastUsedAt: tokenRecord.lastUsedAt.toISOString()
      });

      // Revoke the token immediately
      await prisma.refreshToken.update({
        where: { id: tokenRecord.id },
        data: { revokedAt: new Date() }
      });

      return res.status(401).json({
        success: false,
        error: { code: 'TOKEN_REUSE_DETECTED', message: 'Token reuse detected. Please login again.' }
      });
    }

    // Mark token as used
    await prisma.refreshToken.update({
      where: { id: tokenRecord.id },
      data: { lastUsedAt: new Date() }
    });

    // Generate new tokens...
    const tokens = await generateTokens(tokenRecord.userId);

    await AuditService.logFromRequest(req, 'TOKEN_REFRESH', tokenRecord.userId, {
      tokenId: tokenRecord.id
    });

    res.json({
      success: true,
      data: tokens
    });

  } catch (error) {
    await AuditService.logFromRequest(req, 'TOKEN_REFRESH', undefined, {
      error: 'Internal server error'
    });
    console.error('Token refresh error:', error);
    res.status(500).json({
      success: false,
      error: { code: 'INTERNAL_ERROR', message: 'Internal server error' }
    });
  }
});

